import{_ as b}from"./Pwr0MH4f.js";import{_ as i,a7 as l,c as d,a as o,b as p,Q as n,o as _}from"./BTaHnLwF.js";const v={class:"policy-page"},y={class:"policy-page__container"},c="Политика конфиденциальности — Indigo",s="Политика конфиденциальности интернет-магазина «Индиго».",u={__name:"privacy-policy",setup(r){const e=[{label:"Главная",to:"/"},{label:"Правовая информация",to:"/legal-information"},{label:"Политика конфиденциальности",to:""}];return l({title:c,description:s,ogTitle:c,ogDescription:s}),(m,a)=>{const t=b;return _(),d("main",v,[o("div",y,[p(t,{items:e,class:"policy-page__breadcrumbs"}),a[0]||(a[0]=n('<article class="policy-page__card" data-v-b0cb85ed><h1 class="policy-page__title" data-v-b0cb85ed> Политика конфиденциальности <br data-v-b0cb85ed> интернет-магазина «Индиго» </h1><div class="policy-page__dates" data-v-b0cb85ed><p class="policy-page__date" data-v-b0cb85ed> Дата публикации: «___» __________ 20__ г. </p><p class="policy-page__date" data-v-b0cb85ed> Дата последнего обновления: «___» __________ 20__ г. </p></div><div class="policy-page__content" data-v-b0cb85ed><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>1.</span>Общие положения</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>1.1.</span>Настоящая Политика конфиденциальности (далее — Политика) определяет порядок сбора, хранения, обработки, использования и защиты персональных данных пользователей интернет-магазина «Индиго», расположенного по адресу: [указать URL] (далее — Сайт).</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>1.2.</span>Оператором персональных данных является ИНДИВИДУАЛЬНЫЙ ПРЕДПРИНИМАТЕЛЬ РУЧКО АНАСТАСИЯ ВИКТОРОВНА, ОГРНИП 323930100105541 от 25.01.2023г., ИНН 930900107014, Юридический адрес: РФ, ДНР. Донецкий г.о., 283054, г. Донецк, ул. Аристова, д.1. Фактический адрес: РФ, ДНР. Донецкий г.о., г. Донецк, ул. Постышева, д.60 (далее — Оператор).</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>1.3.</span>Политика разработана в соответствии с Федеральным законом от 27.07.2006 № 152-ФЗ «О персональных данных» (с учётом изменений, вступивших в силу в 2025 году), а также иными нормативно-правовыми актами Российской Федерации в области персональных данных.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>1.4.</span>Используя Сайт, заполняя формы обратной связи, оформляя заказ или регистрируя учётную запись, Пользователь даёт согласие на обработку своих персональных данных в соответствии с настоящей Политикой.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>1.5.</span>Если Пользователь не согласен с условиями Политики, он обязан прекратить использование Сайта.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>1.6.</span>Политика распространяется на все персональные данные, которые Оператор получает от Пользователей через Сайт.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>2.</span>Основные понятия</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>2.1.</span>Персональные данные — любая информация, относящаяся прямо или косвенно к определённому или определяемому физическому лицу (субъекту персональных данных).</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>2.2.</span>Обработка персональных данных — любое действие или совокупность действий с персональными данными: сбор, запись, систематизация, накопление, хранение, уточнение, извлечение, использование, передача, обезличивание, блокирование, удаление, уничтожение.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>2.3.</span>Оператор — лицо, самостоятельно или совместно с другими лицами организующее и осуществляющее обработку персональных данных, а также определяющее цели обработки, состав данных и совершаемые с ними действия.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>2.4.</span>Пользователь — физическое лицо, посещающее Сайт и предоставляющее свои персональные данные через формы на Сайте.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>2.5.</span>Конфиденциальность персональных данных — обязательное требование к Оператору, получившему доступ к персональным данным, не допускать их распространения без согласия субъекта или наличия иного законного основания.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>3.</span>Перечень собираемых персональных данных</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>3.1.</span>Оператор собирает и обрабатывает следующие персональные данные Пользователей:</p><div class="policy-section__block" data-v-b0cb85ed><p class="policy-section__label" data-v-b0cb85ed>При оформлении заказа:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>фамилия, имя, отчество;</li><li data-v-b0cb85ed>номер телефона;</li><li data-v-b0cb85ed>адрес электронной почты;</li><li data-v-b0cb85ed>адрес доставки (город, улица, дом, квартира, почтовый индекс).</li></ul></div><div class="policy-section__block" data-v-b0cb85ed><p class="policy-section__label" data-v-b0cb85ed>При регистрации на Сайте:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>имя;</li><li data-v-b0cb85ed>номер телефона;</li><li data-v-b0cb85ed>адрес электронной почты;</li><li data-v-b0cb85ed>пароль (в зашифрованном виде).</li></ul></div><div class="policy-section__block" data-v-b0cb85ed><p class="policy-section__label" data-v-b0cb85ed>При обращении через форму обратной связи:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>имя;</li><li data-v-b0cb85ed>адрес электронной почты или номер телефона;</li><li data-v-b0cb85ed>текст обращения.</li></ul></div><div class="policy-section__block" data-v-b0cb85ed><p class="policy-section__label" data-v-b0cb85ed>При подписке на рассылку:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>адрес электронной почты;</li><li data-v-b0cb85ed>имя (при указании).</li></ul></div><div class="policy-section__block" data-v-b0cb85ed><p class="policy-section__label" data-v-b0cb85ed>Автоматически при посещении Сайта:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>IP-адрес;</li><li data-v-b0cb85ed>данные файлов cookie;</li><li data-v-b0cb85ed>тип и версия браузера;</li><li data-v-b0cb85ed>тип устройства и разрешение экрана;</li><li data-v-b0cb85ed>источник перехода на Сайт (referrer);</li><li data-v-b0cb85ed>время и дата посещения;</li><li data-v-b0cb85ed>просмотренные страницы.</li></ul></div><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>3.2.</span>Оператор не собирает и не обрабатывает специальные категории персональных данных (расовая принадлежность, политические взгляды, состояние здоровья и т. д.) и биометрические данные.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>3.3.</span>Оператор не проверяет достоверность предоставленных Пользователем данных. Пользователь несёт ответственность за предоставление корректной информации.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>4.</span>Цели обработки персональных данных</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>4.1.</span>Оператор обрабатывает персональные данные в следующих целях:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>оформление и исполнение заказов (подтверждение, сборка, доставка);</li><li data-v-b0cb85ed>связь с Пользователем по вопросам заказа (уведомления о статусе, уточнение деталей);</li><li data-v-b0cb85ed>создание и ведение учётной записи Пользователя в личном кабинете;</li><li data-v-b0cb85ed>обработка обращений и запросов Пользователя через форму обратной связи;</li><li data-v-b0cb85ed>направление информационных и рекламных рассылок (при наличии отдельного согласия);</li><li data-v-b0cb85ed>улучшение работы Сайта и качества обслуживания (анализ посещаемости, поведения пользователей);</li><li data-v-b0cb85ed>соблюдение требований законодательства Российской Федерации (налоговая и бухгалтерская отчётность, 54-ФЗ);</li><li data-v-b0cb85ed>предотвращение мошеннических действий.</li></ul><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>4.2.</span>Обработка персональных данных осуществляется исключительно в целях, указанных в п. 4.1. Данные не используются в целях, не совместимых с заявленными.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>5.</span>Правовые основания обработки</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>5.1.</span>Оператор обрабатывает персональные данные на следующих правовых основаниях:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>согласие Пользователя на обработку персональных данных (ст. 6 ч. 1 п. 1 ФЗ-152);</li><li data-v-b0cb85ed>исполнение договора, стороной которого является Пользователь, — оформление и доставка заказа (ст. 6 ч. 1 п. 5 ФЗ-152);</li><li data-v-b0cb85ed>соблюдение обязанностей, предусмотренных законодательством (ст. 6 ч. 1 п. 2 ФЗ-152);</li><li data-v-b0cb85ed>законные интересы Оператора — улучшение качества обслуживания, предотвращение мошенничества (ст. 6 ч. 1 п. 7 ФЗ-152).</li></ul></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>6.</span>Порядок обработки персональных данных</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>6.1.</span>Обработка персональных данных осуществляется автоматизированным способом с использованием средств вычислительной техники и информационных систем.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>6.2.</span>Персональные данные хранятся на серверах, расположенных на территории Российской Федерации, в соответствии с требованиями ч. 5 ст. 18 ФЗ-152.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>6.3.</span>Оператор обеспечивает запись, систематизацию, накопление, хранение, уточнение, извлечение персональных данных с использованием баз данных, находящихся на территории Российской Федерации.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>7.</span>Сроки обработки и хранения</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>7.1.</span>Персональные данные обрабатываются и хранятся в течение срока, необходимого для достижения целей обработки:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>данные заказов — в течение срока действия договора и 5 (пяти) лет после его исполнения (в соответствии с требованиями налогового и бухгалтерского законодательства);</li><li data-v-b0cb85ed>данные учётной записи — до момента удаления учётной записи Пользователем или по запросу Пользователя;</li><li data-v-b0cb85ed>данные подписки на рассылку — до отписки Пользователя;</li><li data-v-b0cb85ed>данные обращений — 1 (один) год с момента обращения;</li><li data-v-b0cb85ed>данные файлов cookie — в соответствии с настройками браузера Пользователя, но не более 1 (одного) года.</li></ul><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>7.2.</span>По истечении сроков хранения персональные данные уничтожаются или обезличиваются.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>8.</span>Передача персональных данных третьим лицам</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>8.1.</span>Оператор вправе передавать персональные данные третьим лицам в следующих случаях:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>службам доставки — для доставки заказа (фамилия, имя, телефон, адрес доставки);</li><li data-v-b0cb85ed>платёжным системам и банкам-эквайерам — для проведения оплаты (передача осуществляется в защищённом режиме, Оператор не хранит данные банковских карт);</li><li data-v-b0cb85ed>операторам фискальных данных и онлайн-кассам — для формирования и отправки чеков в соответствии с 54-ФЗ;</li><li data-v-b0cb85ed>сервисам аналитики (Яндекс.Метрика, Google Analytics) — обезличенные данные для анализа посещаемости;</li><li data-v-b0cb85ed>сервисам email-рассылок — для отправки рассылок (при наличии согласия);</li><li data-v-b0cb85ed>государственным органам — по запросу в случаях, предусмотренных законодательством РФ.</li></ul><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>8.2.</span>При передаче данных Оператор заключает с третьими лицами соглашения, обязывающие их обеспечивать конфиденциальность и безопасность полученных данных.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>8.3.</span>Оператор не продаёт и не передаёт персональные данные третьим лицам в рекламных целях без явного согласия Пользователя.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>9.</span>Защита персональных данных</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>9.1.</span>Оператор принимает необходимые организационные и технические меры для защиты персональных данных от несанкционированного доступа, уничтожения, изменения, блокирования, копирования, распространения и иных неправомерных действий.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>9.2.</span>Меры защиты включают:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>использование протокола HTTPS для шифрования данных при передаче между Пользователем и Сайтом;</li><li data-v-b0cb85ed>хранение паролей в зашифрованном виде (хэширование);</li><li data-v-b0cb85ed>ограничение доступа сотрудников к персональным данным (доступ предоставляется только тем сотрудникам, которым он необходим для выполнения должностных обязанностей);</li><li data-v-b0cb85ed>регулярное обновление программного обеспечения и систем безопасности;</li><li data-v-b0cb85ed>резервное копирование данных;</li><li data-v-b0cb85ed>контроль доступа к серверам и информационным системам.</li></ul><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>9.3.</span>Оператор не хранит данные банковских карт Пользователей. Платежи обрабатываются сертифицированными платёжными системами, соответствующими стандарту PCI DSS.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>10.</span>Файлы cookie</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>10.1.</span>Сайт использует файлы cookie — небольшие текстовые файлы, сохраняемые на устройстве Пользователя для обеспечения работы Сайта и анализа его использования.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>10.2.</span>Используемые типы cookie:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>необходимые — обеспечивают работу корзины, авторизации и основных функций Сайта;</li><li data-v-b0cb85ed>аналитические — помогают понять, как Пользователи взаимодействуют с Сайтом (Яндекс.Метрика, Google Analytics);</li><li data-v-b0cb85ed>маркетинговые — используются для показа релевантной рекламы (при наличии).</li></ul><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>10.3.</span>Пользователь может отключить или ограничить использование cookie в настройках своего браузера. Отключение cookie может привести к ограничению функциональности Сайта (невозможность добавить товар в корзину, авторизоваться и др.).</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>11.</span>Права Пользователя</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>11.1.</span>Пользователь вправе:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>получить информацию об обработке своих персональных данных (перечень данных, цели обработки, сроки хранения, кому передаются);</li><li data-v-b0cb85ed>потребовать уточнения, обновления или исправления своих персональных данных;</li><li data-v-b0cb85ed>потребовать удаления своих персональных данных;</li><li data-v-b0cb85ed>отозвать согласие на обработку персональных данных;</li><li data-v-b0cb85ed>потребовать прекращения обработки персональных данных в целях продвижения товаров и услуг (отказ от рассылки);</li><li data-v-b0cb85ed>обжаловать действия или бездействие Оператора в уполномоченный орган по защите прав субъектов персональных данных (Роскомнадзор) или в судебном порядке.</li></ul><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>11.2.</span>Для реализации своих прав Пользователь может направить письменный запрос Оператору: по электронной почте: info@indigo-mail.ru и уведомить оператора по телефону +7 949 499 69 79;</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>11.3.</span>Оператор рассматривает запрос в течение 10 (десяти) рабочих дней с момента получения и направляет ответ Пользователю.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>11.4.</span>Отзыв согласия на обработку персональных данных может повлечь невозможность использования отдельных функций Сайта (личный кабинет, оформление заказа). Данные, обработка которых обусловлена законодательством (налоговая отчётность), сохраняются до истечения установленных сроков.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>12.</span>Обработка данных несовершеннолетних</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>12.1.</span>Сайт не предназначен для лиц младше 18 лет. Оператор не собирает персональные данные несовершеннолетних намеренно.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>12.2.</span>Если Оператору станет известно, что персональные данные были предоставлены несовершеннолетним без согласия законного представителя, такие данные будут удалены.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>13.</span>Ответственный за обработку персональных данных</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>13.1.</span>Ответственным за организацию обработки персональных данных назначен: ИНДИВИДУАЛЬНЫЙ ПРЕДПРИНИМАТЕЛЬ РУЧКО АНАСТАСИЯ ВИКТОРОВНА.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>13.2.</span>Контактные данные ответственного лица:</p><ul class="policy-section__list" data-v-b0cb85ed><li data-v-b0cb85ed>электронная почта: info@indigo-mail.ru</li><li data-v-b0cb85ed>телефон: +7 949-499-69-79</li></ul></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>14.</span>Уведомление Роскомнадзора</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>14.1.</span>Оператор подал уведомление об обработке персональных данных в Роскомнадзор в соответствии со ст. 22 ФЗ-152.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>14.2.</span>Сведения об Операторе внесены в реестр операторов персональных данных. Проверить запись можно на сайте Роскомнадзора: https://pd.rkn.gov.ru/operators-registry/operators-list/</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>15.</span>Изменение Политики</h2><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>15.1.</span>Оператор вправе вносить изменения в настоящую Политику. Новая редакция вступает в силу с момента её публикации на Сайте по адресу: [указать URL страницы политики].</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>15.2.</span>Дата последнего обновления указана в начале документа.</p><p class="policy-section__text" data-v-b0cb85ed><span class="policy-section__subnumber" data-v-b0cb85ed>15.3.</span>Продолжение использования Сайта после публикации изменений означает согласие Пользователя с новой редакцией Политики.</p></section><section class="policy-section" data-v-b0cb85ed><h2 class="policy-section__title" data-v-b0cb85ed><span class="policy-section__number" data-v-b0cb85ed>16.</span>Реквизиты Оператора</h2><div class="policy-page__requisites" data-v-b0cb85ed><p class="policy-page__text policy-page__text_strong" data-v-b0cb85ed> ИНДИВИДУАЛЬНЫЙ ПРЕДПРИНИМАТЕЛЬ <br data-v-b0cb85ed> РУЧКО АНАСТАСИЯ ВИКТОРОВНА </p><p class="policy-page__text" data-v-b0cb85ed> ИНН 930900107014, ОГРНИП 323930100105541 <br data-v-b0cb85ed> Юр. Адрес: ДНР, 283054, г. Донецк, Донецкий округ, ул. Аристова, д.1, <br data-v-b0cb85ed> р/с 40802810100810222405 в российских рублях, ФИЛИАЛ &quot;ЦЕНТРАЛЬНЫЙ&quot; <br data-v-b0cb85ed> БАНКА ВТБ, (ПАО), г Москва. БИК 044525411 30101810145250000411 <br data-v-b0cb85ed> Тел.: +7 949-499-69-79, <br data-v-b0cb85ed> E-mail: info@indigo-mail.ru </p><p class="policy-page__text" data-v-b0cb85ed> ИП </p><p class="policy-page__text" data-v-b0cb85ed> ____________________А.В. Ручко </p></div></section></div></article>',1))])])}}},g=i(u,[["__scopeId","data-v-b0cb85ed"]]);export{g as default};
